import { Injectable } from '@angular/core';
import { HttpClient,HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { EquipCategorias } from '../models/equip-categorias'; 


@Injectable({
  providedIn: 'root'
})
export class EquipsService {


  constructor(private http: HttpClient) { }

  getEquipamentosPorSubcategoria(subcategoria: string): Observable<EquipCategorias[]> {
    const url = `https://ced.discloud.app/api/categorias-de-equipamento/${subcategoria}`;
    return this.http.get<EquipCategorias[]>(url);
  }

}
